"use strict";(globalThis.webpackChunkdoqumentation=globalThis.webpackChunkdoqumentation||[]).push([[9116],{10550(e,n,i){i.r(n),i.d(n,{assets:()=>u,contentTitle:()=>d,default:()=>o,frontMatter:()=>a,metadata:()=>s,toc:()=>l});const s=JSON.parse('{"id":"learning/courses/quantum-computing-in-practice/applications-of-qc","title":"F\xfcr welche Probleme sind Quantencomputer geeignet?","description":"Erfahre, wie wir entscheiden, welche Arten von Problemen von einer Quantenl\xf6sung profitieren k\xf6nnten, und sieh dir einige aktuelle Beispiele aus der Community an.","source":"@site/i18n/de/docusaurus-plugin-content-docs/current/learning/courses/quantum-computing-in-practice/applications-of-qc.mdx","sourceDirName":"learning/courses/quantum-computing-in-practice","slug":"/learning/courses/quantum-computing-in-practice/applications-of-qc","permalink":"/learning/courses/quantum-computing-in-practice/applications-of-qc","draft":false,"unlisted":false,"editUrl":"https://github.com/JanLahmann/doQumentation/tree/main/docs/learning/courses/quantum-computing-in-practice/applications-of-qc.mdx","tags":[],"version":"current","frontMatter":{"title":"F\xfcr welche Probleme sind Quantencomputer geeignet?","sidebar_label":"F\xfcr welche Probleme sind Quantencomputer geeignet?","description":"Erfahre, wie wir entscheiden, welche Arten von Problemen von einer Quantenl\xf6sung profitieren k\xf6nnten, und sieh dir einige aktuelle Beispiele aus der Community an.","notebook_path":"learning/courses/quantum-computing-in-practice/applications-of-qc.ipynb"},"sidebar":"tutorialsSidebar","previous":{"title":"Utility-Scale QAOA","permalink":"/learning/courses/quantum-computing-in-practice/utility-scale-qaoa"},"next":{"title":"Abbildung (Mapping)","permalink":"/learning/courses/quantum-computing-in-practice/mapping"}}');var r=i(74848),t=i(28453);const a={title:"F\xfcr welche Probleme sind Quantencomputer geeignet?",sidebar_label:"F\xfcr welche Probleme sind Quantencomputer geeignet?",description:"Erfahre, wie wir entscheiden, welche Arten von Problemen von einer Quantenl\xf6sung profitieren k\xf6nnten, und sieh dir einige aktuelle Beispiele aus der Community an.",notebook_path:"learning/courses/quantum-computing-in-practice/applications-of-qc.ipynb"},d=void 0,u={},l=[{value:"Einleitung",id:"introduction",level:2},{value:"Klassische vs. quantenmechanische Schwierigkeit",id:"classical-vs-quantum-difficulty",level:2},{value:"Komplexit\xe4tsklassen",id:"complexity-classes",level:3},{value:"Die heutigen Quantencomputer und ihre Grenzen",id:"todays-quantum-computers-and-their-limits",level:3},{value:"Anwendungsbereiche und Anwendungsf\xe4lle",id:"application-areas-and-use-cases",level:2},{value:"Anwendungsfall 1: Simulation von Hadronen-Dynamik",id:"use-case-1-simulating-hadron-dynamics",level:3},{value:"Anwendungsfall 2: Optimierung eines Ising-Spin-Glases",id:"use-case-2-optimization-of-an-ising-spin-glass",level:3},{value:"Anwendungsfall 3: Vorhersage der mRNA-Sekund\xe4rstruktur",id:"use-case-3-mrna-secondary-structure-prediction",level:3},{value:"Fazit",id:"conclusion",level:2}];function h(e){const n={a:"a",annotation:"annotation",h2:"h2",h3:"h3",img:"img",li:"li",math:"math",mi:"mi",mn:"mn",mo:"mo",mrow:"mrow",ol:"ol",p:"p",semantics:"semantics",span:"span",ul:"ul",...(0,t.R)(),...e.components},{IBMVideo:s}=n;return s||function(e,n){throw new Error("Expected "+(n?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("IBMVideo",!0),(0,r.jsxs)(r.Fragment,{children:["\n","\n",(0,r.jsxs)(n.p,{children:["Schau dir das Video zu Anwendungen des Quantencomputings von Olivia Lanes an, oder \xf6ffne es in einem separaten Fenster auf ",(0,r.jsx)(n.a,{href:"https://youtu.be/33QmsXhIlpU",children:"YouTube."})]}),"\n",(0,r.jsx)(s,{id:"134063426",title:"In diesem Video beschreibt Olivia Lanes mehrere m\xf6gliche Anwendungen des Quantencomputings im Utility-Ma\xdfstab. Dazu geh\xf6ren die Simulation von Hadronen und Spin-Gl\xe4sern sowie die Modellierung von Proteinstrukturen."}),"\n",(0,r.jsx)(n.h2,{id:"introduction",children:"Einleitung"}),"\n",(0,r.jsx)(n.p,{children:"In der vorherigen Lektion haben wir uns eingehend mit einem einzigen Problem befasst \u2013 dem L\xf6sen des Max-Cut-Optimierungsproblems mithilfe der QUBO-Formulierung. Heute gehen wir einen anderen Weg und diskutieren Nahzeit-Anwendungen in einem breiteren Rahmen. Wir beginnen damit, dir ein Gef\xfchl daf\xfcr zu geben, wie wir entscheiden, welche Arten von Problemen von einer Quantenl\xf6sung profitieren k\xf6nnten. Anschlie\xdfend schauen wir uns einige aktuelle Arbeiten aus unserer Community an. Das soll dir helfen, ein Gesp\xfcr f\xfcr die verschiedenen Arten von Quantencomputing-Problemen zu entwickeln und zu verstehen, wie wir sie angehen."}),"\n",(0,r.jsx)(n.h2,{id:"classical-vs-quantum-difficulty",children:"Klassische vs. quantenmechanische Schwierigkeit"}),"\n",(0,r.jsx)(n.p,{children:"Bevor wir in die Beispiele einsteigen, lass uns zun\xe4chst dar\xfcber sprechen, wie wir die Schwierigkeit verschiedener Probleme untersuchen und einordnen. Einige Probleme lassen sich leicht auf einem klassischen Computer l\xf6sen, und wir brauchen daf\xfcr keinen Quantencomputer. Auf der anderen Seite gibt es sehr schwere Probleme, f\xfcr die Quantencomputer notwendig sind. Ein bekanntes Beispiel ist die Primfaktorzerlegung riesiger ganzer Zahlen. Die RSA-Verschl\xfcsselung beruht auf der Schwierigkeit dieses Problems, und Shor's Algorithmus wurde entwickelt, um es auf einem Quantencomputer zu l\xf6sen. Ein weiteres Beispiel ist die Suche nach einer L\xf6sung in einem unsortierten Datensatz \u2013 das kann theoretisch durch den als Grover-Algorithmus bekannten Quantenalgorithmus gel\xf6st werden. Die meisten Experten sind sich jedoch einig, dass diese Arten von Algorithmen die Implementierung von Fehlerkorrektur erfordern und die Technologie daf\xfcr noch nicht bereit ist."}),"\n",(0,r.jsx)(n.p,{children:"Wir suchen also nach Problemen, die wir irgendwo in einer Mitte zwischen sehr einfach und sehr schwer angehen k\xf6nnen \u2013 solche, die die Quantencomputer von heute bew\xe4ltigen k\xf6nnen, die aber klassischen Computern Schwierigkeiten bereiten."}),"\n",(0,r.jsx)(n.h3,{id:"complexity-classes",children:"Komplexit\xe4tsklassen"}),"\n",(0,r.jsx)(n.p,{children:"Die Schwierigkeit dieser Probleme wird in einem Teilgebiet der Informatik namens Berechnungskomplexit\xe4tstheorie kategorisiert und analysiert. Es gibt eine Vielzahl verschiedener Komplexit\xe4tsklassen im klassischen Computing, aber einige der grundlegendsten sind:"}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsx)(n.li,{children:"P: Probleme, die in polynomieller Zeit l\xf6sbar sind, wenn die Problemgr\xf6\xdfe zunimmt. Sie sind einfach zu l\xf6sen."}),"\n",(0,r.jsx)(n.li,{children:"NP: Das steht f\xfcr nichtdeterministisch polynomial. Diese Probleme k\xf6nnen nicht notwendigerweise in polynomieller Zeit gel\xf6st werden, aber ihre Antworten lassen sich in polynomieller Zeit verifizieren."}),"\n",(0,r.jsx)(n.li,{children:"NP-vollst\xe4ndig sind die schwierigsten Probleme in NP und haben keine bekannte polynomielle L\xf6sung. Hier leben ber\xfchmte Probleme wie das Travelling-Salesman-Problem und das Spiel Sudoku."}),"\n",(0,r.jsx)(n.li,{children:"BPP, oder Bounded-Error Polynomial Problems, die von einem probabilistischen klassischen Computer in polynomieller Zeit innerhalb einer gewissen Fehlergrenze gel\xf6st werden k\xf6nnen."}),"\n"]}),"\n",(0,r.jsx)(n.p,{children:"Als das Konzept des Quantencomputings erfunden wurde, haben viele Forscher erhebliche Anstrengungen unternommen, um herauszufinden, welche Klasse von Problemen diese neuen Computertypen effizient l\xf6sen k\xf6nnten. Eine neue Klasse von Problemen wurde eingef\xfchrt:"}),"\n",(0,r.jsxs)(n.ul,{children:["\n",(0,r.jsx)(n.li,{children:"BQP, oder Bounded-Error Quantum Polynomial Problems. Dies ist das quantenmechanische \xc4quivalent von BPP: Es ist die Klasse von Entscheidungsproblemen, die von einem Quantencomputer in polynomieller Zeit mit einer kleinen Fehlerwahrscheinlichkeit l\xf6sbar sind."}),"\n"]}),"\n",(0,r.jsx)(n.p,{children:(0,r.jsx)(n.img,{alt:"Vermutete Beziehungen zwischen Komplexit\xe4tsklassen",src:i(52600).A+"",width:"976",height:"682"})}),"\n",(0,r.jsx)(n.p,{children:"Alle diese Klassen leben in einer gr\xf6\xdferen Klasse, die wir PSPACE nennen. Oben ist ein Diagramm der vermuteten Beziehungen zwischen einigen Komplexit\xe4tsklassen, aber dies ist mathematisch sehr schwer definitiv zu beweisen. Du wirst feststellen, dass BQP sich nicht unbedingt mit NP-vollst\xe4ndig \xfcberschneidet. Dennoch gibt es Quantencomputing-Ans\xe4tze, die versuchen, Probleme in NP-vollst\xe4ndig zu l\xf6sen."}),"\n",(0,r.jsx)(n.p,{children:"Ein h\xe4ufiges Missverst\xe4ndnis ist, dass es keinen Sinn ergibt, Quantenl\xf6sungen f\xfcr Probleme zu erforschen, f\xfcr die kein mathematischer Beweis f\xfcr eine Quantenbeschleunigung gefunden wurde. Aber einen mathematischen Beweis daf\xfcr zu finden, dass ein Quantenalgorithmus schneller als sein klassisches Gegenst\xfcck ist, ist schwierig. Shor's und Grover's sind zwei der bisher wenigen Beispiele, bei denen dies gelungen ist. Tats\xe4chlich ist der rigorose Beweis, dass P und NP verschieden sind, eine der bekanntesten offenen Fragen in der gesamten Mathematik, obwohl alle Intuitionen darauf hindeuten, dass dies der Fall sein muss."}),"\n",(0,r.jsx)(n.p,{children:"Die Art und Weise, wie ein Algorithmus mit wachsender Problemgr\xf6\xdfe skaliert \u2013 was in der Komplexit\xe4tsklasse widergespiegelt wird \u2013 ist jedoch nicht immer das relevanteste Merkmal eines Algorithmus. Diese Skalierung ist oft das Worst-Case-Szenario. Es ist durchaus m\xf6glich, dass wir in der Praxis nicht am h\xe4ufigsten auf das Worst-Case-Szenario sto\xdfen."}),"\n",(0,r.jsx)(n.p,{children:"Nur weil Schwierigkeitsbeweise knifflig sind, bedeutet das nicht, dass wir keinen Fortschritt machen k\xf6nnen. Wir f\xfchren die Idee heuristischer L\xf6sungen ein. Wenn du Experimentalist bist, kennst und liebst du wahrscheinlich diese Art von L\xf6sungen. Eine Heuristik ist jeder Ansatz zur L\xf6sung eines Problems, der pragmatisch, aber nicht notwendigerweise optimal ist, da L\xf6sungen nicht optimal sein m\xfcssen, um n\xfctzlich zu sein. Denk zum Beispiel an finanzielle Anwendungen. Wir haben noch keine exponentielle Beschleunigung f\xfcr die meisten Finanzalgorithmen gefunden, bei denen Quanten eingesetzt werden k\xf6nnten, aber wir brauchen keine optimale L\xf6sung. Im Finanzwesen k\xf6nnte selbst eine L\xf6sung, die nur 0,1% effizienter ist, Milliarden von Dollar Gewinn bedeuten."}),"\n",(0,r.jsx)(n.h3,{id:"todays-quantum-computers-and-their-limits",children:"Die heutigen Quantencomputer und ihre Grenzen"}),"\n",(0,r.jsx)(n.p,{children:"Wie wissen wir also, welche Anwendungsf\xe4lle und Probleme derzeit f\xfcr das Quantencomputing geeignet sein k\xf6nnten? Gibt es gute Gr\xfcnde zu glauben, dass Quantum Utility oder sogar Quantum Advantage jetzt oder in naher Zukunft gefunden werden kann?"}),"\n",(0,r.jsx)(n.p,{children:"Vielleicht ist es einfacher, zun\xe4chst die Dinge zu benennen, die das Problem sicher nicht haben sollte. Es kann keine riesige Anzahl von Qubits erfordern. Wir haben noch keine Prozessoren mit Tausenden bis Millionen von Qubits verf\xfcgbar. Das ist einer der Hauptgr\xfcnde, warum Shor's Algorithmus und \xe4hnliche noch so weit von der Realisierung entfernt sind. Die Circuits k\xf6nnen auch nicht zu tief sein. Die Grenze der Circuit-Tiefe h\xe4ngt von vielen Faktoren ab, aber im Allgemeinen gilt: Wenn dein Experiment eine Tiefe erfordert, die du noch nicht in der Literatur gesehen hast, wird es wahrscheinlich nicht funktionieren. Und schlie\xdflich k\xf6nnen noch keine Algorithmen, von denen wir wissen, dass sie Fehlerkorrektur erfordern, umgesetzt werden."}),"\n",(0,r.jsxs)(n.p,{children:["All diese Einschr\xe4nkungen werden in der ",(0,r.jsx)(n.a,{href:"https://www.ibm.com/quantum/technology#roadmap",children:"IBM Quantum\xae Roadmap"})," adressiert, und wir erwarten, Fehlerkorrektur in den fr\xfchen 2030er Jahren zu erreichen. F\xfcr jetzt aber m\xfcssen wir nach Experimenten suchen, die die meisten der derzeit auf einem QPU verf\xfcgbaren Qubits nutzen. Wir betonen auch die Bedeutung von Error Mitigation und Error Suppression. Und schlie\xdflich sollte es eine offensichtliche Erweiterung auf zuk\xfcnftige Anwendungen geben, die f\xfcr die Gesellschaft wichtig w\xe4ren und die uns letztendlich zu einem Quantum Advantage f\xfchren k\xf6nnten."]}),"\n",(0,r.jsx)(n.h2,{id:"application-areas-and-use-cases",children:"Anwendungsbereiche und Anwendungsf\xe4lle"}),"\n",(0,r.jsx)(n.p,{children:"Lass uns nun \xfcber einige Beispiele f\xfcr Anwendungsf\xe4lle sprechen, die in drei Hauptkategorien fallen, die wir als am wahrscheinlichsten f\xfcr g\xfcnstige Ergebnisse im nahen bis mittelfristigen Zeitraum identifiziert haben:"}),"\n",(0,r.jsxs)(n.ol,{children:["\n",(0,r.jsxs)(n.li,{children:["\n",(0,r.jsxs)(n.p,{children:["Natursimulationen. Aktuelle klassische Methoden der atomaren und molekularen Simulationen sind durch ineffiziente mathematische Beschreibungen der Atomstruktur begrenzt. Das Speichern und Manipulieren eines Quantenzustands erfordert exponentiell viele Ressourcen auf einem klassischen Computer, kann aber effizient auf einem Quantencomputer durchgef\xfchrt werden. Dies k\xf6nnte zu Entwicklungen bei der CO\u2082-Sequestrierung, alternativen Batterien oder der Erfindung neuer Medikamente f\xfchren. Einige besonders relevante Algorithmen in diesem Bereich sind: der Variational Quantum Eigensolver (VQE), der zur Sch\xe4tzung bestimmter Eigenschaften eines Materials wie Gleichgewichts- oder Minimalenergiezust\xe4nde verwendet wird; der Time Dynamics Simulation (TDS)-Algorithmus, der zur Sch\xe4tzung von Antwortfunktionen oder spektralen Eigenschaften von Materialien verwendet wird; und ein Newcomer, ",(0,r.jsx)(n.a,{href:"/learning/courses/quantum-diagonalization-algorithms/sqd-overview",children:"Sample-based Quantum Diagonalization (SQD)"}),", von dem wir glauben, dass wir in naher Zukunft noch viel mehr h\xf6ren werden."]}),"\n"]}),"\n",(0,r.jsxs)(n.li,{children:["\n",(0,r.jsx)(n.p,{children:"Optimierung. Dieser Bereich ist allgegenw\xe4rtig im Computing, daher sind die Anwendungsf\xe4lle zahlreich und vielf\xe4ltig. Einige Beispiele, die wir h\xe4ufig h\xf6ren, sind Portfoliooptimierung im Finanzwesen, industrielles Design sowie Verteilung und Lieferkette. Der h\xe4ufigste Algorithmus, den du im Zusammenhang mit dem Finanzwesen wahrscheinlich h\xf6ren wirst, ist der, den wir bereits ausf\xfchrlich behandelt haben: der Quantum Approximate Optimization Algorithm oder QAOA."}),"\n"]}),"\n",(0,r.jsxs)(n.li,{children:["\n",(0,r.jsx)(n.p,{children:"Quantum Machine Learning. Dieser Bereich hat in den letzten Jahren viel Begeisterung erzeugt, aber es ist wahrscheinlich, dass QML nicht so bald n\xfctzlich sein wird wie die Simulation. Dennoch gibt es einige beeindruckende Algorithmen, an denen gearbeitet wird, um einige sehr wichtige Anwendungsf\xe4lle anzugehen. Einige dieser m\xf6glichen Anwendungsf\xe4lle sind nat\xfcrliche Sprachverarbeitung, Netzwerkverkehrsanalyse und sogar Betrugserkennung bei Finanztransaktionen. Relevante Algorithmen in diesem Bereich sind die Quantum Support Vector Machine (QSVM), Quantum Neural Networks (QNN) und Quantum Generative Adversarial Networks."}),"\n"]}),"\n"]}),"\n",(0,r.jsx)(n.p,{children:"Innerhalb dieser breiten Anwendungsbereiche sieht die Community den Nutzen darin, dass Gruppen zusammenarbeiten, die sich auf ein spezifischeres Thema konzentrieren. IBM\xae hat eine Initiative namens Working Groups ins Leben gerufen, um Mitarbeitern zu helfen, sich gegenseitig zu finden und produktive Synergien in vier spezifischen Bereichen zu schaffen: Gesundheitswesen und Biowissenschaften, Materialien und High-Performance Computing (HPC), Hochenergiephysik und Optimierung. K\xfcrzlich wurde auch eine f\xfcnfte Working Group zum Thema Nachhaltigkeit gegr\xfcndet."}),"\n",(0,r.jsx)(n.p,{children:"Wir werden uns jetzt einige Probleme genauer ansehen, die k\xfcrzlich von einigen dieser Working Groups bearbeitet wurden. Das Hauptziel dabei ist nicht, jedes Detail eines Experiments zu verstehen \u2013 das kann selbst f\xfcr Experten schwierig sein, wenn das Papier leicht au\xdferhalb ihres Fachgebiets liegt. Das Ziel ist lediglich, ein Gesp\xfcr f\xfcr die Arten von Problemen zu entwickeln, f\xfcr die Quantencomputer geeignet sind, und wie wir sie angehen. Und wenn du interessiert bist, ermutigen wir dich, die vollst\xe4ndigen Papiere zu lesen."}),"\n",(0,r.jsx)(n.h3,{id:"use-case-1-simulating-hadron-dynamics",children:"Anwendungsfall 1: Simulation von Hadronen-Dynamik"}),"\n",(0,r.jsxs)(n.p,{children:["Zun\xe4chst werden wir uns in ein Paper von Martin Savages Gruppe an der University of Washington vertiefen, das ",(0,r.jsx)(n.a,{href:"https://journals.aps.org/prd/abstract/10.1103/PhysRevD.109.114510",children:"Quantum Simulations of Hadron Dynamics in the Schwinger Model Using 112 Qubits"})," hei\xdft."]}),"\n",(0,r.jsx)(n.p,{children:'Auch wenn du kein Hochenergiephysiker bist, bist du vielleicht mit dem Begriff \u201eHadron" vertraut, wie im Large Hadron Collider (LHC), dem riesigen Teilchenbeschleuniger mit einem Umfang von 27 km, der es schlie\xdflich erm\xf6glichte, das Higgs-Boson zu beobachten. Ein Hadron ist ein subatomares zusammengesetztes Teilchen, das aus anderen kleinen Teilchen namens Quarks besteht. Einige Beispiele f\xfcr Hadronen sind Neutronen und Protonen.'}),"\n",(0,r.jsx)(n.p,{children:"Zum Kontext: Der LHC wurde gebaut, um das Studium der Grundlagenphysik durch das Aufeinanderprallen von Teilchen bei extrem hohen Energien zu erm\xf6glichen. Mit dem LHC hoffen Wissenschaftler, mehr \xfcber das fr\xfche Universum und die Grundgesetze der Natur zu erfahren. Prinzipiell k\xf6nnten die Wechselwirkungen dieser Teilchen mit einem ausreichend leistungsf\xe4higen Quantencomputer von Anfang bis Ende simuliert werden. Wir sind noch nicht ganz so weit, aber wir machen Fortschritte."}),"\n",(0,r.jsx)(n.p,{children:"Das Schwinger-Modell ist ein popul\xe4res, einfaches Modell, das zur Simulation einiger dieser Dynamiken verwendet wird. Es ist ein Modell, das das Verhalten von Elektronen und Positronen beschreibt, die in 1+1D \xfcber Photonen wechselwirken, also in Zeit und einer r\xe4umlichen Dimension. Das Modell hat viele \xc4hnlichkeiten mit der Quantenchromodynamik (QCD), die beschreibt, wie Quarks und Hadronen wechselwirken, aber QCD ist extrem schwer zu simulieren. Daher wird das Schwinger-Modell oft als Spielzeugmodell verwendet, um einige Ph\xe4nomene zu untersuchen, die beiden gemeinsam sind."}),"\n",(0,r.jsx)(n.p,{children:"Um zu verstehen, warum sie dieses Problem angegangen sind, stellen wir uns eine Reihe von Fragen."}),"\n",(0,r.jsx)(n.p,{children:"Erstens, warum hatten sie Grund zu glauben, dass die Simulation davon auf einem Quantencomputer \xfcberhaupt funktionieren w\xfcrde? In diesem Fall haben die Elektronen und Positronen im Schwinger-Modell einen Abschirmeffekt, der dazu f\xfchrt, dass Korrelationen zwischen weit entfernten Fermionen exponentiell mit der Entfernung abnehmen. Das bedeutet, dass es nicht so viele notwendige Fernwechselwirkungen von einem Qubit auf einer Seite des Chips zu einer anderen gibt, was bekannterma\xdfen sehr fehleranf\xe4llig ist. Das ist also ideal f\xfcr die Hardware, die wir heute haben."}),"\n",(0,r.jsx)(n.p,{children:"Als n\xe4chstes: Warum ist dieses Thema von Interesse? Hochenergiephysik ist im Allgemeinen von gro\xdfem Interesse. Die Menschen waren bereit, Milliarden von Dollar auszugeben, um den LHC zu bauen, und viele Tausende von Wissenschaftlern und Technikern auf der ganzen Welt haben ihre Karriere diesem Bereich gewidmet. Obwohl das Schwinger-Modell simplistisch ist und nicht f\xfcr drei r\xe4umliche Dimensionen ausgelegt ist, ist es dennoch eine n\xfctzliche Vereinfachung der vollst\xe4ndigen Theorie."}),"\n",(0,r.jsx)(n.p,{children:"Schlie\xdflich: Wie wurde diese Arbeit durchgef\xfchrt, oder wie w\xfcrden wir das Problem angehen, wenn wir diese Arbeit fortsetzen wollten? Bei Simulationsexperimenten ist VQE einer der h\xe4ufigsten Ans\xe4tze, und der erste Schritt ist fast immer derselbe: den Grundzustand vorbereiten. In diesem Fall handelt es sich um einen Vakuumzustand. In diesem Experiment verwenden sie eine neue Version von VQE namens SC-ADAPT-VQE (was f\xfcr Scalable Circuits - Adaptive Derivative-Assembled Pseudo-Trotter ansatz-VQE steht), um sowohl den Grundzustand als auch das Hadronen-Wellenpaket auf diesem Vakuum vorzubereiten. Der n\xe4chste Schritt besteht darin, die Hadronen sich zeitlich entwickeln zu lassen. Schlie\xdflich werden die zu messenden Observablen identifiziert und gemessen."}),"\n",(0,r.jsx)(n.p,{children:"Wenn diese Schritte \u2013 abgesehen vom Hadronen-Wellenpaket-Teil \u2013 etwas vertraut klingen, liegt das daran, dass sie dem, was wir im QAOA-Beispiel in der vorherigen Lektion behandelt haben, sehr \xe4hnlich sind. Wir beginnen in einem bekannten Zustand (hier dem Vakuumzustand) und lassen ihn dann mit einer Reihe von exponentierten Hamiltonianern in der Zeit entwickeln. Viele Variationsalgorithmen folgen diesem allgemeinen Ansatz. Ein gro\xdfer Unterschied hier ist jedoch, dass wir das Hadronen-Wellenpaket zentriert in unserem Circuit erzeugen, bevor wir es sich entwickeln lassen."}),"\n",(0,r.jsx)(n.p,{children:"Wie erzeugen wir also das Wellenpaket? Auf dem Vakuum kann ein Hadron angeregt werden, indem ein Fermion-Antifermion-Paar auf benachbarten Gitterpl\xe4tzen erzeugt wird. Durch Vorbereitung einer Superposition solcher Hadronen an verschiedenen Positionen kann ein beliebiges Wellenpaket vorbereitet werden. Die Autoren haben ihr Wellenpaket in der Mitte des Circuits zentriert, um die Evolution zu beobachten, ohne eine Grenze zu treffen."}),"\n",(0,r.jsx)(n.p,{children:"Aber denk daran: Das Spiel beim Arbeiten mit verrauschten QPUs besteht darin, die Circuit-Tiefe handhabbar zu halten. Dazu verwendet das SC-ADAPT-VQE-Protokoll Symmetrien und Hierarchien in L\xe4ngenskalen, um tiefenarme Quantencircuits f\xfcr die Zustandspr\xe4paration zu bestimmen. Dies erzeugt einen Ansatz mit einer kleineren Anzahl von Parametern und damit einer geringeren Tiefe."}),"\n",(0,r.jsx)(n.p,{children:"Das Experiment wurde auf einem IBM Quantum Heron-Ger\xe4t durchgef\xfchrt und umfasste verschiedene Arten von Error Mitigation und Error Suppression: Dynamical Decoupling, Zero Noise Extrapolation, Pauli Twirling und eine k\xfcrzlich entwickelte Technik namens Operator Decoherence Renormalization."}),"\n",(0,r.jsx)(n.p,{children:(0,r.jsx)(n.img,{alt:"Ergebnisse der Hadronen-Simulationen",src:i(77894).A+"",width:"1158",height:"838"})}),"\n",(0,r.jsx)(n.p,{children:"Oben ist eine Abbildung aus dem Paper, die die interessierende Observable zeigt, das chirale Kondensat, das im Wesentlichen eine suprafluide Phase der Hadronen ist. Wir k\xf6nnen das Wellenpaket in der Mitte der Gitterpl\xe4tze sehen, die f\xfcr dieses Experiment vorgesehen wurden. Die schwarzen Linien sind die fehlerfreien Ergebnisse aus der (rechnerisch aufw\xe4ndigen) klassischen Simulation, w\xe4hrend die Punkte mit Fehlerbalken die Ergebnisse des 133-Qubit-IBM-Quantencomputers Torino sind."}),"\n",(0,r.jsxs)(n.p,{children:["Wir sehen zwei verschiedene Zeitschritte in der Wellenpaketvolution. Bei Zeit ",(0,r.jsxs)(n.span,{className:"katex",children:[(0,r.jsx)(n.span,{className:"katex-mathml",children:(0,r.jsx)(n.math,{xmlns:"http://www.w3.org/1998/Math/MathML",children:(0,r.jsxs)(n.semantics,{children:[(0,r.jsxs)(n.mrow,{children:[(0,r.jsx)(n.mi,{children:"t"}),(0,r.jsx)(n.mo,{children:"="}),(0,r.jsx)(n.mn,{children:"1"})]}),(0,r.jsx)(n.annotation,{encoding:"application/x-tex",children:"t=1"})]})})}),(0,r.jsxs)(n.span,{className:"katex-html","aria-hidden":"true",children:[(0,r.jsxs)(n.span,{className:"base",children:[(0,r.jsx)(n.span,{className:"strut",style:{height:"0.6151em"}}),(0,r.jsx)(n.span,{className:"mord mathnormal",children:"t"}),(0,r.jsx)(n.span,{className:"mspace",style:{marginRight:"0.2778em"}}),(0,r.jsx)(n.span,{className:"mrel",children:"="}),(0,r.jsx)(n.span,{className:"mspace",style:{marginRight:"0.2778em"}})]}),(0,r.jsxs)(n.span,{className:"base",children:[(0,r.jsx)(n.span,{className:"strut",style:{height:"0.6444em"}}),(0,r.jsx)(n.span,{className:"mord",children:"1"})]})]})]})," ist das chirale Kondensat schmal und lokalisiert, und es stimmt auch gut mit der klassischen Simulation \xfcberein. Bei ",(0,r.jsxs)(n.span,{className:"katex",children:[(0,r.jsx)(n.span,{className:"katex-mathml",children:(0,r.jsx)(n.math,{xmlns:"http://www.w3.org/1998/Math/MathML",children:(0,r.jsxs)(n.semantics,{children:[(0,r.jsxs)(n.mrow,{children:[(0,r.jsx)(n.mi,{children:"t"}),(0,r.jsx)(n.mo,{children:"="}),(0,r.jsx)(n.mn,{children:"14"})]}),(0,r.jsx)(n.annotation,{encoding:"application/x-tex",children:"t=14"})]})})}),(0,r.jsxs)(n.span,{className:"katex-html","aria-hidden":"true",children:[(0,r.jsxs)(n.span,{className:"base",children:[(0,r.jsx)(n.span,{className:"strut",style:{height:"0.6151em"}}),(0,r.jsx)(n.span,{className:"mord mathnormal",children:"t"}),(0,r.jsx)(n.span,{className:"mspace",style:{marginRight:"0.2778em"}}),(0,r.jsx)(n.span,{className:"mrel",children:"="}),(0,r.jsx)(n.span,{className:"mspace",style:{marginRight:"0.2778em"}})]}),(0,r.jsxs)(n.span,{className:"base",children:[(0,r.jsx)(n.span,{className:"strut",style:{height:"0.6444em"}}),(0,r.jsx)(n.span,{className:"mord",children:"14"})]})]})]})," ist es viel weiter ausgebreitet. Der Vergleich mit dem Simulator ist jetzt nicht mehr ganz so perfekt, aber man kann immer noch eine sehr gute \xdcbereinstimmung zwischen Theorie und Daten erkennen, was ermutigend ist."]}),"\n",(0,r.jsx)(n.p,{children:"Zusammenfassend ist dies ein sehr cooles Beispiel f\xfcr die Art von Simulationsarbeit, auf die man zun\xe4chst vielleicht nicht denkt, Quantencomputing anzuwenden, das aber echtes Versprechen zeigt. Es ist nicht perfekt, aber man muss kein Teilchenphysik-Experte sein, um zu sehen, dass der Quantencomputer die nach au\xdfen gerichtete Ausbreitung des Wellenpakets genau vorhersagt, was genau das ist, was wir erwarten w\xfcrden. Hoffentlich wird die zuk\xfcnftige Arbeit in diesem Bereich fortgesetzt, und Hochenergiephysiker werden weiterhin Wege finden, Quantencomputing in ihre Arbeitsabl\xe4ufe einzubinden. Das Ziel ist es, schwierige theoretische Probleme pr\xe4ziser zu l\xf6sen und Experimente zu nutzen, um Theorien zu best\xe4tigen oder zu verwerfen, in der Hoffnung, neue Physik zu entdecken, verbesserte Detektoren zu bauen und zu einem besseren Verst\xe4ndnis der Natur auf ihrer fundamentalsten Ebene zu gelangen."}),"\n",(0,r.jsx)(n.h3,{id:"use-case-2-optimization-of-an-ising-spin-glass",children:"Anwendungsfall 2: Optimierung eines Ising-Spin-Glases"}),"\n",(0,r.jsxs)(n.p,{children:["Unser n\xe4chstes Beispiel konzentriert sich auf Optimierung und wird ein tiefer Einblick in ein Paper namens ",(0,r.jsx)(n.a,{href:"https://arxiv.org/abs/2405.13898",children:"Bias-Field Digitized Counterdiabatic Quantum Optimization"})," sein, das von Mitgliedern des Kipu-Quantum-Teams und der Universit\xe4t des Baskenlandes in Spanien durchgef\xfchrt wurde."]}),"\n",(0,r.jsx)(n.p,{children:'In dem Paper entwickelten die Autoren eine neue Optimierungsmethode und wandten sie an, um den Grundzustand eines Ising-Spin-Glases zu finden. Wie bereits besprochen, k\xf6nnen viele kombinatorische Optimierungsprobleme als L\xf6sung von Niedrigenergie-Zust\xe4nden von Ising-Hamiltonianern umformuliert werden. Das Ising-Modell beschreibt die Wechselwirkung einer Anordnung mikroskopischer Spins. In einigen Regimen sagt das Modell voraus, dass sich die Spins wie ein Glas verhalten, bei dem die magnetischen Momente oberhalb einer sogenannten \u201eGefriertemperatur" ungeordnet sind.'}),"\n",(0,r.jsx)(n.p,{children:"Wir beginnen wie zuvor mit einer Reihe von Definitionen. Das erste ist gegendiabatisch (counterdiabatic), was eine Art Evolution ist, die nicht-adiabatische Effekte eines Systems unterdr\xfcckt, unabh\xe4ngig davon, wie schnell diese Prozesse stattfinden. Erinnere dich an das adiabatische Theorem aus der letzten Episode \u2013 du musst ein System normalerweise sehr langsam entwickeln, wenn es im Grundzustand bleiben soll. Das ist ein gro\xdfes Problem, denn je langsamer wir die Dinge entwickeln m\xfcssen, desto mehr Zeit haben wir f\xfcr Fehler. Counterdiabatic Driving (CD) zielt darauf ab, dies zu bek\xe4mpfen, indem Terme hinzugef\xfcgt werden, die diesen unerw\xfcnschten Anregungen entgegenwirken. Die Grundidee besteht darin, das gesamte Experiment zu beschleunigen und die Circuit-Tiefe zu reduzieren, indem Anregungen unterdr\xfcckt werden, die unerw\xfcnschte \xdcberg\xe4nge verursachen k\xf6nnten."}),"\n",(0,r.jsx)(n.p,{children:"Nun zum anderen Fachbegriff im Titel: das Bias-Feld. Andere iterative Algorithmen, wie VQE, f\xfchren klassische Parameter in die Zust\xe4nde ein und verwenden klassische Optimierer, um den hochdimensionalen Parameterraum nach dem Satz von Parametern zu durchsuchen, der einen minimalen Erwartungswert f\xfcr einen festen Hamiltonianer ergibt. In diesem Fall variieren sie stattdessen den Hamiltonianer jedes Mal und bewegen sich adiabatisch von einem bekannten Fall zum Fall von Interesse. Um den Hamiltonianer zu \xe4ndern, wenden sie einfach den Pauli-Z-Erwartungswert aus einer Iteration direkt als Bias-Feld im Hamiltonianer f\xfcr die n\xe4chste Iteration an. Auf diese Weise lenken sie die Dynamik in Richtung der tats\xe4chlichen L\xf6sung, ohne klassische Optimierer zu ben\xf6tigen."}),"\n",(0,r.jsx)(n.p,{children:"Warum ist dieses Experiment also von Interesse? Ising-Spin-Gl\xe4ser sind in der Physik von grundlegendem Interesse, aber dieser neue Ansatz ist sogar noch allgemeiner. Er k\xf6nnte auf viele Optimierungsprobleme angewendet werden, daher ist das Paper von breitem Interesse."}),"\n",(0,r.jsx)(n.p,{children:"Und warum dachten wir, das w\xfcrde funktionieren? Der von ihnen vorgeschlagene Algorithmus beschleunigt die Evolution, um die Circuit-Tiefe zu reduzieren und dabei nicht-adiabatische \xdcberg\xe4nge zu unterdr\xfccken. Au\xdferdem st\xfctzt er sich auf keine klassischen Optimierungsunterroutinen, die ein Problem f\xfchren k\xf6nnen, das zu kahlen Plateaus und dem Feststecken in lokalen Minima f\xfchrt. Schlie\xdflich stellen die Autoren auch sicher, die Wechselwirkungen im Problem-Hamiltonianer mit der Hardware-Konnektivit\xe4t in den realen QPUs auszurichten, was immer sehr wichtig ist."}),"\n",(0,r.jsx)(n.p,{children:"Wie funktioniert diese Methode also? Wieder verwendet sie keine klassischen Optimierer, anders als die meisten anderen iterativen Quantenalgorithmen. Stattdessen verfeinert der Bias-Field Digitized Quantum Optimization-Algorithmus den Grundzustand inkrementell und bringt ihn n\xe4her und n\xe4her an den endg\xfcltig entwickelten Zustand heran, indem er die L\xf6sung aus jeder Iteration in die Eingabe f\xfcr die n\xe4chste einspeist. Kombiniert mit den gegendiabatischen Protokollen k\xf6nnen wir dies sogar mit kurztiefigen Quantencircuits tun, die reibungslos auf verrauschter Hardware laufen sollten."}),"\n",(0,r.jsx)(n.p,{children:"Als das Experiment durchgef\xfchrt wurde, entschieden die Autoren, den Algorithmus auf dem 127-Qubit-IBM-Quantencomputer Brisbane auszuf\xfchren. Unten ist eine Abbildung, die die 8. Iteration des Optimierungsalgorithmus f\xfcr eine n\xe4chste-Nachbar-, zuf\xe4llig generierte Spin-Glas-Instanz auf 100 Qubits zeigt. Sie vergleichen idealisierte klassische Simulationsergebnisse von DCQO und BF-DCQO sowie das experimentelle Ergebnis, das auf dem Quantencomputer ausgef\xfchrt wurde. Sie zeigen auch das Ergebnis eines klassischen L\xf6sers namens Gurobi als Referenz. Mit nur 10 Iterationen liefert BF-DCQO eine drastische Verbesserung im Vergleich zu DCQO. Obwohl das experimentelle Ergebnis aufgrund von Rauschen etwas anders als das ideale Ergebnis ist, ist die Leistung immer noch besser als das ideale DCQO. Dies zeigt, dass noch immer erhebliche Fortschritte bei der Quantenoptimierung erzielt werden und erstmals gute Ergebnisse f\xfcr \xfcber 100 Qubits gemeldet werden."}),"\n",(0,r.jsx)(n.p,{children:(0,r.jsx)(n.img,{alt:"Ergebnisse aus dem Ising-Spin-Glas-Paper",src:i(43410).A+"",width:"976",height:"682"})}),"\n",(0,r.jsx)(n.h3,{id:"use-case-3-mrna-secondary-structure-prediction",children:"Anwendungsfall 3: Vorhersage der mRNA-Sekund\xe4rstruktur"}),"\n",(0,r.jsxs)(n.p,{children:["Schlie\xdflich werden wir ein Paper von Moderna Pharmaceuticals diskutieren, das ",(0,r.jsx)(n.a,{href:"https://arxiv.org/abs/2405.20328",children:"mRNA Secondary Structure Prediction Using Utility-Scale Quantum Computers"})," hei\xdft."]}),"\n",(0,r.jsx)(n.p,{children:"Zun\xe4chst eine kurze Auffrischung \xfcber mRNA. Messenger-RNA ist eine Art RNA, die an der Proteinsynthese beteiligt ist. Sie liest im Wesentlichen Anweisungen, die von der DNA gegeben werden. Die Sekund\xe4rstruktur der mRNA ist, wie die Kette gefaltet ist, wie im Diagramm unten gezeigt. Und das mRNA-Sekund\xe4rstruktur-Vorhersageproblem ist das Problem, die stabilste Faltung der Sequenz von Basen oder Nukleotiden zu finden, aus denen RNA besteht: Adenin (A), Cytosin (C), Uracil (U) und Guanin (G). Das Bild unten zeigt einige h\xe4ufige Faltungsstrukturen, die in mRNA gefunden werden; jede Farbe stellt einen anderen Typ von Sekund\xe4rstruktur dar. Was eine Struktur g\xfcnstiger macht als die anderen, ist nicht gut verstanden; wir k\xf6nnen nur berechnen, welche Struktur die niedrigste freie Energie im Vergleich zum ungefalteten Zustand ergibt. Und genau hier kommen Quantencomputer ins Spiel."}),"\n",(0,r.jsx)(n.p,{children:(0,r.jsx)(n.img,{alt:"Diagramm der mRNA-Sekund\xe4rstruktur",src:i(41923).A+"",width:"638",height:"842"})}),"\n",(0,r.jsx)(n.p,{children:"Warum sind mRNA-Sekund\xe4rstrukturen also wichtig? Eine genaue Vorhersage davon ist nicht nur f\xfcr das Verst\xe4ndnis der DNA und unserer Gene entscheidend, sondern auch f\xfcr das Design RNA-basierter Therapeutika, wie dem COVID-19-Impfstoff."}),"\n",(0,r.jsx)(n.p,{children:"Es ist seit langem bekannt, dass dies ein gewaltiges Optimierungsproblem f\xfcr klassische Computer ist, aufgrund der riesigen Anzahl m\xf6glicher Konfigurationen. F\xfcr einige Konfigurationen ist bekannt, dass es sich um ein NP-vollst\xe4ndiges Problem handelt. Auf einem Quantencomputer k\xf6nnen wir jedoch die Sekund\xe4rstrukturvorhersage als bin\xe4res Optimierungsproblem formulieren \u2013 etwas, mit dem wir umzugehen wissen. Dar\xfcber hinaus gab es bereits in der Literatur Beweise f\xfcr genaue RNA-Vorhersagen auf kleinen Quantenger\xe4ten und Quantensimulatoren. Aber w\xfcrde das auch auf gr\xf6\xdferer Hardware funktionieren?"}),"\n",(0,r.jsx)(n.p,{children:"Dieses Experiment wurde mit dem sogenannten Conditional Value at Risk Variational Quantum Eigensolver durchgef\xfchrt, was eine Modifikation eines traditionellen VQE-Algorithmus ist und eine bessere Konvergenz erzielen soll."}),"\n",(0,r.jsx)(n.p,{children:(0,r.jsx)(n.img,{alt:"Ergebnisse aus dem mRNA-Paper",src:i(65188).A+"",width:"1158",height:"686"})}),"\n",(0,r.jsx)(n.p,{children:"Der obige Plot zeigt die Verteilung der Messprobabilit\xe4ten der abgetasteten Bitstrings mit den entsprechenden Energien f\xfcr eine 42-Nukleotid-, 80-Qubit-Instanz. Hier symbolisieren die Bitstrings Paarungen von Nukleotiden. Es zeigt, dass der niedrigste Energie-Bitstring, den der Quantencomputer gefunden hat, mit dem des vergleichenden klassischen L\xf6sers \xfcbereinstimmt \u2013 das ist gro\xdfartig. Ebenfalls gezeigt wird die optimale Faltungsstruktur dieser Nukleotidkette basierend auf dem niedrigsten Energie-Bitstring, den der Quantencomputer gefunden hat."}),"\n",(0,r.jsx)(n.h2,{id:"conclusion",children:"Fazit"}),"\n",(0,r.jsx)(n.p,{children:"Hoffentlich haben diese drei Anwendungsf\xe4lle dir genug Kontext gegeben, um zu verstehen, wie modernste Arbeit auf diesem Gebiet derzeit aussieht, und das Vertrauen, neue Quantenexperimente zu versuchen, die du vorher vielleicht nicht ausprobiert h\xe4ttest."}),"\n",(0,r.jsx)(n.p,{children:"Denke daran: Quantencomputing ist nicht f\xfcr jedes Problem geeignet. Und das ist eigentlich nur ein Zeugnis daf\xfcr, wie gut wir im klassischen Computing geworden sind. Nur weil du glaubst, Quantencomputing auf ein Problem anwenden zu k\xf6nnen, bedeutet das nicht, dass es interessante Ergebnisse liefern wird; du musst die Skalierung ber\xfccksichtigen."}),"\n",(0,r.jsx)(n.p,{children:"Die Circuit-Tiefe ist ein zweischneidiges Schwert. Wir brauchen sie, um interessante Arbeit zu leisten, die klassische Computer nicht k\xf6nnen, aber im Moment k\xf6nnen wir die Tiefe nicht zu sehr erh\xf6hen, weil das Hardware-Rauschen die Fidelit\xe4t verringern wird. Es geht darum, diese goldene Mitte zu finden und zu wissen, dass es ein sich bewegendes Ziel ist. Also nimm dir etwas Zeit bis zur n\xe4chsten Lektion, um \xfcber ein Problem nachzudenken, dem du in deiner Forschung begegnet bist, und wie du es mit dem angehen k\xf6nntest, was wir bisher gelernt haben. Und hey, deine L\xf6sung muss nicht aufgehen, und das ist in Ordnung. Daf\xfcr betreiben wir ja Forschung."})]})}function o(e={}){const{wrapper:n}={...(0,t.R)(),...e.components};return n?(0,r.jsx)(n,{...e,children:(0,r.jsx)(h,{...e})}):h(e)}},52600(e,n,i){i.d(n,{A:()=>s});const s=i.p+"assets/images/complexity_classes-52979b588e98706373f7abc9b3f5f57c.avif"},77894(e,n,i){i.d(n,{A:()=>s});const s=i.p+"assets/images/hadron_paper-bc9c0a13fc3cd0e44b5c193902ce6dba.avif"},65188(e,n,i){i.d(n,{A:()=>s});const s=i.p+"assets/images/mrna_paper-4b1d694275f2539f69c49bfbb9b5ddd8.avif"},41923(e,n,i){i.d(n,{A:()=>s});const s=i.p+"assets/images/mrna_structure-962f2d5dfb98ac0a2e9c680e23d97ada.avif"},43410(e,n,i){i.d(n,{A:()=>s});const s=i.p+"assets/images/paper_results-aace6d8c4b97868e6cba7fc772e13ad9.avif"},28453(e,n,i){i.d(n,{R:()=>a,x:()=>d});var s=i(96540);const r={},t=s.createContext(r);function a(e){const n=s.useContext(t);return s.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function d(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:a(e.components),s.createElement(t.Provider,{value:n},e.children)}}}]);